(function(w){"use strict";const ID="circle";function compute(x){const r=Number(x.radius);if(!Number.isFinite(r)||r<0)return{error:"반지름에 0 이상의 숫자를 입력해 주세요."};return{radius:r,diameter:2*r,circumference:2*Math.PI*r,area:Math.PI*r*r}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label for="hm-circle-r">반지름 r</label><input id="hm-circle-r" class="hm-calc-input" inputmode="decimal" placeholder="예: 5"></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">원 계산하기</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const r=root.querySelector("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const o=compute({radius:r.value});if(o.error){api.setMessage(msg,o.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("원의 넓이",api.formatNumber(o.area,10),`<dl><dt>둘레</dt><dd>${api.formatNumber(o.circumference,10)}</dd><dt>지름</dt><dd>${api.formatNumber(o.diameter,10)}</dd></dl>`));});reset.addEventListener("click",()=>{r.value="";api.setMessage(msg,"");api.clearResult(res);r.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
